"""Const Contracts

Five programs that violate const correctness. Fix them all.
"""
import os, shutil, subprocess, sys, tempfile, zipfile
import hashlib as _hl, hmac as _hm

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "bbdc43ea48a0fb7725c25a8a55e5f6dcfd36b6881cdda99adc802abfdb38912b063c7ab88e932792272d71432f1deeba2822"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

def _compile_run(src, name, repo_dir):
    binary = os.path.join(repo_dir, name)
    r = subprocess.run(
        ["g++", "-std=c++17", "-o", binary, os.path.join(repo_dir, src)],
        capture_output=True, text=True,
    )
    if r.returncode != 0:
        return None, r.stderr
    try:
        run = subprocess.run([binary], capture_output=True, text=True, timeout=10)
    except subprocess.TimeoutExpired:
        return None, "timeout"
    return run.stdout.strip(), None

_PROGRAMS = [
    ("label.cpp",  "label"),
    ("censor.cpp", "censor"),
    ("scan.cpp",   "scan"),
    ("locate.cpp", "locate"),
    ("report.cpp", "report"),
]

def _check_const_cast(repo_dir):
    for src, _ in _PROGRAMS:
        path = os.path.join(repo_dir, src)
        try:
            with open(path) as f:
                if "const_cast" in f.read():
                    return src
        except OSError:
            pass
    return None

def _all_binaries_exist(repo_dir):
    return all(os.path.isfile(os.path.join(repo_dir, name)) for _, name in _PROGRAMS)

def _validate(repo_dir):
    outputs = []
    for src, name in _PROGRAMS:
        out, err = _compile_run(src, name, repo_dir)
        if out is None:
            return False, "compile-error", src, err
        outputs.append(out)
    key_str = "|".join(outputs)
    return True, key_str, None, None

def main():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")

    work_dir = tempfile.mkdtemp(prefix="const-contract-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    repo_dir = os.path.join(work_dir, entries[0])

    banner_text = """
      ============================================================
       Const Contracts
      ============================================================

       Five programs.  Each has a const violation.  Fix them all.
       
         Each file has a comment explaining what the bug is and what to fix.
         After editing, rebuild with 'make' to see if the compile errors are gone.
       
         Step 1 -- read the error in label.cpp and fix the parameter type.
           g++ -std=c++17 label.cpp && ./label
       
         Step 2 -- fix censor.cpp: the function must not mutate through const char*.
           g++ -std=c++17 censor.cpp && ./censor
       
         Step 3 -- fix scan.cpp: the wrong kind of const is on the pointer.
           g++ -std=c++17 scan.cpp && ./scan
       
         Step 4 -- fix locate.cpp: the return type strips const from the input.
           g++ -std=c++17 locate.cpp && ./locate
       
         Step 5 -- fix report.cpp: two related bugs, fix tag_of first.
           g++ -std=c++17 report.cpp && ./report
       
         When all five compile and run, type 'exit'.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@const-contract:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << \'BANNER\'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()

    shell = os.environ.get("SHELL", "/bin/bash")

    try:
        while True:
            subprocess.run([shell, "--rcfile", rcfile.name])

            cast_file = _check_const_cast(repo_dir)
            if cast_file:
                print()
                print(f"  const_cast found in {cast_file}.")
                print("  Fix the type rather than casting away const.")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            if not _all_binaries_exist(repo_dir):
                print()
                print("  Please compile all five programs before exiting:")
                for src, name in _PROGRAMS:
                    print(f"    g++ -std=c++17 -o {name} {src}")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            print()
            _banner("Const Contracts -- Checking Your Work")
            print()

            ok, key_str, which, detail = _validate(repo_dir)

            if ok:
                passphrase = _decrypt(key_str)
                if passphrase is not None:
                    _show_passphrase(passphrase)
                    break
                print("  All five compiled and ran, but the output was not correct.")
                print("  Check that each program prints the expected line.")
            elif key_str == "compile-error":
                if detail == "timeout":
                    print(f"  {which} did not finish in time.")
                else:
                    print(f"  {which} did not compile.  Error:")
                    for line in detail.strip().splitlines():
                        print(f"    {line}")

            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                break
            if again == "y":
                print()
                continue
            break

    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass
        shutil.rmtree(work_dir, ignore_errors=True)


if __name__ == "__main__":
    main()
